import { expect, it } from 'vitest'

import { camelCaseKeys } from './camelcase-keys.js'

it('Camelcase Basic', ctx => {
  const object = {
    lowercase: 1,
    'Title Case': 2,
    'kebab-case': 3,
    PascalCase: 4,
  }

  const expected = {
    lowercase: 1,
    titleCase: 2,
    kebabCase: 3,
    pascalCase: 4,
  }

  const result = camelCaseKeys(object)
  expect(result).toEqual(expected)
})

it('Camelcase Nested', ctx => {
  const object = {
    one: {
      lowercase: 1,
      'Title Case': 2,
      'kebab-case': 3,
      PascalCase: 4,
    },
  }

  const expected = {
    one: {
      lowercase: 1,
      titleCase: 2,
      kebabCase: 3,
      pascalCase: 4,
    },
  }

  const result = camelCaseKeys(object)
  expect(result).toEqual(expected)
})

it('Camelcase Deeply Nested', ctx => {
  const object = {
    one: {
      two: {
        lowercase: 1,
        'Title Case': 2,
        'kebab-case': 3,
        PascalCase: 4,
      },
    },
  }

  const expected = {
    one: {
      two: {
        lowercase: 1,
        titleCase: 2,
        kebabCase: 3,
        pascalCase: 4,
      },
    },
  }

  const result = camelCaseKeys(object)
  expect(result).toEqual(expected)
})
